    "How comfortable would you be seeing someone who practices a different religion from you: Pray in public using some kind of physical object (rosary, tefillin, etc)" AS how_comfortable_would_you_be_seeing_someone_who_practices_a_different_religion_from_you_pray_in_public_using_some_kind_of_physical_object_rosary_tefillin_etc,
    "How comfortable would you be seeing someone who practices a different religion from you: Pray aloud before meals in the presence of people who don't belong to that religion" AS how_comfortable_would_you_be_seeing_someone_who_practices_a_different_religion_from_you_pray_aloud_before_meals_in_the_presence_of_people_who_don_t_belong_to_that_religion,
    "How comfortable would you be seeing someone who practices a different religion from you: Tell someone ""I'll pray for you""" AS how_comfortable_would_you_be_seeing_someone_who_practices_a_different_religion_from_you_tell_someone_i_ll_pray_for_you,
