    "How comfortable would you be seeing someone who practices a different religion from you: Decline some kind of food or beverage for religious reasons (kosher, halal, fasting rules, etc)" AS how_comfortable_would_you_be_seeing_someone_who_practices_a_different_religion_from_you_decline_some_kind_of_food_or_beverage_for_religious_reasons_kosher_halal_fasting_rules_etc,
    "How comfortable would you be seeing someone who practices a different religion from you: Wear religious clothing/jewelry (hijab, kippah, wig, kara, turban, cross, etc)" AS how_comfortable_would_you_be_seeing_someone_who_practices_a_different_religion_from_you_wear_religious_clothing_jewelry_hijab_kippah_wig_kara_turban_cross_etc,
    "How comfortable would you be seeing someone who practices a different religion from you: Participate in a public religious event on the streets (Corpus Christi procession, inauguration of Torah scrolls, etc)" AS how_comfortable_would_you_be_seeing_someone_who_practices_a_different_religion_from_you_participate_in_a_public_religious_event_on_the_streets_corpus_christi_procession_inauguration_of_torah_scrolls_etc,
